"use client"

import React, { useMemo } from "react"
import Link from "next/link"
import { motion } from "framer-motion"
import { Button } from "@/components/ui/button"
import { ArrowRight, ShieldCheck, Globe, Zap, Users, Building2 } from "lucide-react"

/**
 * VOXEL GRID COMPONENT
 * Generates a 100-cube sea using CSS 3D transforms.
 * Each cube is a "Voxel" representing a modular unit of engineering.
 */
const VoxelSea = () => {
  const voxels = useMemo(() => {
    const grid = []
    const size = 10 // 10x10 grid = 100 cubes
    for (let x = 0; x < size; x++) {
      for (let y = 0; y < size; y++) {
        grid.push({
          id: `${x}-${y}`,
          x: (x - size / 2) * 110, 
          y: (y - size / 2) * 110,
          // Perlin-style delay based on coordinates to create wave motion
          delay: (Math.sin(x * 0.5) + Math.cos(y * 0.5)) * 2,
          duration: 4 + Math.random() * 2,
        })
      }
    }
    return grid
  }, [])

  return (
    <div className="absolute inset-0 z-0 overflow-hidden bg-slate-950 perspective-[2000px]">
      {/* 3D Container with Perspective Tilt */}
      <div className="absolute inset-0 flex items-center justify-center [transform-style:preserve-3d] rotate-x-[60deg] -rotate-z-[45deg] scale-75 lg:scale-110">
        {voxels.map((v) => (
          <div
            key={v.id}
            className="absolute [transform-style:preserve-3d] animate-voxel-wave"
            style={{
              left: `calc(50% + ${v.x}px)`,
              top: `calc(50% + ${v.y}px)`,
              animationDelay: `${v.delay}s`,
              animationDuration: `${v.duration}s`,
            } as React.CSSProperties}
          >
            {/* The 3D Cube */}
            <div className="relative w-24 h-24 [transform-style:preserve-3d]">
              {/* TOP FACE: Internal Glow & Emissive Lighting */}
              <div className="absolute inset-0 bg-primary/20 backdrop-blur-md border border-white/20 translate-z-[48px] flex items-center justify-center">
                 <div className="w-full h-full bg-primary/30 animate-pulse-slow rounded-sm" />
              </div>
              
              {/* FRONT FACE: Frosted Glass */}
              <div className="absolute inset-0 bg-white/10 backdrop-blur-sm border border-white/10 origin-bottom rotate-x-[-90deg] translate-y-[48px]" />
              
              {/* RIGHT FACE */}
              <div className="absolute inset-0 bg-white/5 backdrop-blur-sm border border-white/5 origin-left rotate-y-[90deg] -translate-x-[48px]" />
              
              {/* LEFT FACE */}
              <div className="absolute inset-0 bg-white/5 border border-white/5 origin-right rotate-y-[-90deg] translate-x-[48px]" />
              
              {/* BOTTOM FACE */}
              <div className="absolute inset-0 bg-slate-900 translate-z-[-48px]" />
            </div>
          </div>
        ))}
      </div>
      
      {/* Ambient Gradient Overlay to soften the grid edges */}
      <div className="absolute inset-0 z-10 bg-gradient-to-t from-slate-950 via-transparent to-slate-950/50 pointer-events-none" />
    </div>
  )
}

/**
 * GLASSMORPHIC METRIC CARD
 * Integrates perfectly with the voxel background using backdrop-blur-2xl.
 */
function MetricCard({ value, label, icon: Icon }: { value: string; label: string; icon: any }) {
  return (
    <div className="group relative p-6 rounded-3xl bg-white/5 backdrop-blur-2xl border border-white/10 hover:border-primary/50 transition-all duration-500 shadow-2xl">
      <div className="flex items-center gap-4">
        <div className="p-3 rounded-2xl bg-primary/10 text-primary group-hover:scale-110 transition-transform">
          <Icon size={24} />
        </div>
        <div>
          <div className="text-2xl font-bold text-white tracking-tight">{value}</div>
          <div className="text-xs font-bold uppercase tracking-widest text-slate-400">{label}</div>
        </div>
      </div>
    </div>
  )
}

export default function HeroSection() {
  return (
    <section className="relative min-h-screen flex items-center justify-center overflow-hidden">
      {/* Background Component */}
      <VoxelSea />

      {/* Main Content Interface */}
      <div className="container relative z-20 mx-auto px-6 py-24">
        <div className="max-w-4xl">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8 }}
          >
            <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-primary/10 border border-primary/20 mb-8">
              <ShieldCheck className="w-4 h-4 text-primary" />
              <span className="text-[10px] font-bold uppercase tracking-[0.2em] text-primary">
                Enterprise Modular Engineering
              </span>
            </div>

            <h1 className="text-6xl md:text-8xl font-black text-white tracking-tighter leading-[0.85] mb-8">
              BUILDING THE <br />
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary via-blue-400 to-indigo-500">
                VOXEL FUTURE.
              </span>
            </h1>

            <p className="text-xl text-slate-400 max-w-2xl mb-12 leading-relaxed">
              QuantixLabs specializes in high-fidelity infrastructure. We transform 
              complex enterprise requirements into scalable, modular digital ecosystems.
            </p>

            <div className="flex flex-wrap gap-6 mb-20">
              <Button size="lg" className="h-16 px-10 rounded-2xl bg-primary hover:bg-primary/90 text-white font-bold group" asChild>
                <Link href="/contact">
                  Start Building
                  <ArrowRight className="ml-2 w-5 h-5 group-hover:translate-x-1 transition-transform" />
                </Link>
              </Button>
              <Button variant="outline" size="lg" className="h-16 px-10 rounded-2xl border-white/10 bg-white/5 backdrop-blur-md text-white hover:bg-white/10" asChild>
                <Link href="/projects">View Architecture</Link>
              </Button>
            </div>

            {/* Metric Grid Overlay */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              <MetricCard value="12+" label="Sectors" icon={Building2} />
              <MetricCard value="99.9%" label="Reliability" icon={Zap} />
              <MetricCard value="150+" label="Deployments" icon={Globe} />
              <MetricCard value="24/7" label="Ops Center" icon={Users} />
            </div>
          </motion.div>
        </div>
      </div>

      {/* CSS Animations */}
      <style jsx global>{`
        @keyframes voxel-wave {
          0%, 100% { transform: translateZ(0px); }
          50% { transform: translateZ(40px); }
        }
        .animate-voxel-wave {
          animation: voxel-wave linear infinite;
        }
        @keyframes pulse-slow {
          0%, 100% { opacity: 0.2; transform: scale(0.95); }
          50% { opacity: 0.6; transform: scale(1.05); }
        }
        .animate-pulse-slow {
          animation: pulse-slow 3s ease-in-out infinite;
        }
        .perspective-2000 {
          perspective: 2000px;
        }
      `}</style>
    </section>
  )
}